"use client";

import React, { useMemo, useState } from 'react';
import { useQuery } from "@tanstack/react-query";
import { createClient } from "@/lib/supabase/client";
import { usePersona } from "@/hooks/usePersona";
import IndustrialSidebar from "@/components/shell/IndustrialSidebar";
import { useSidebarState } from "@/hooks/useSidebarState";
import { 
  ChevronLeft, Banknote,
  FileText, BarChart3,
  MapPin, Phone, CreditCard,
  Clock, Award
} from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";
import Link from "next/link";
import { useParams } from "next/navigation";
import { Decimal } from "decimal.js";
import Image from 'next/image';

// --- Types ---

interface ProductionLog {
  id: string;
  log_date: string;
  unit: string;
  qty_produced: number;
  effective_earning: number;
}

interface AttendanceLog {
  id: string;
  log_date: string;
  status: 'present' | 'absent' | 'half_day' | 'leave' | 'holiday';
  notes: string | null;
}

interface Advance {
  id: string;
  advance_date: string;
  amount: number;
  reason: string;
  status: 'pending' | 'cleared';
}

// --- Main Component ---

export default function KarigarProfilePage() {
  const { karigarId } = useParams();
  const { isCollapsed } = useSidebarState();
  const { fmt, fmtDate, workerTerm } = usePersona();
  const supabase = createClient();

  const [activeTab, setActiveTab] = useState<'production' | 'attendance' | 'advances' | 'payslips'>('production');

  // Queries
  const { data: karigar, isLoading: karigarLoading } = useQuery({
    queryKey: ['karigar', karigarId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('karigars')
        .select('*, karigar_grades(grade_name)')
        .eq('id', karigarId)
        .single();
      if (error) throw error;
      return data;
    },
    enabled: !!karigarId,
  });

  const { data: productionLogs = [] } = useQuery({
    queryKey: ['karigar_production', karigarId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('karigar_production_logs')
        .select('*')
        .eq('karigar_id', karigarId)
        .order('log_date', { ascending: false });
      if (error) throw error;
      return data as ProductionLog[];
    },
    enabled: !!karigarId,
  });

  const { data: attendanceLogs = [] } = useQuery({
    queryKey: ['karigar_attendance', karigarId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('attendance_logs')
        .select('*')
        .eq('karigar_id', karigarId)
        .order('log_date', { ascending: false });
      if (error) throw error;
      return data as AttendanceLog[];
    },
    enabled: !!karigarId,
  });

  const { data: advances = [] } = useQuery({
    queryKey: ['karigar_advances', karigarId],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('karigar_advances')
        .select('*')
        .eq('karigar_id', karigarId)
        .order('created_at', { ascending: false });
      if (error) throw error;
      return data as Advance[];
    },
    enabled: !!karigarId,
  });

  // Derived Stats
  const tenure = useMemo(() => {
    if (!karigar?.joining_date) return "---";
    const start = new Date(karigar.joining_date);
    const end = new Date();
    const diffTime = Math.abs(end.getTime() - start.getTime());
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    const years = Math.floor(diffDays / 365);
    const months = Math.floor((diffDays % 365) / 30);
    return `${years}y ${months}m`;
  }, [karigar]);

  const monthlyEarnings = useMemo(() => {
    const today = new Date();
    const monthStart = new Date(today.getFullYear(), today.getMonth(), 1).toISOString().split('T')[0];
    const total = productionLogs
      .filter((l: ProductionLog) => l.log_date >= monthStart)
      .reduce((acc: Decimal, l: ProductionLog) => acc.plus(new Decimal(l.effective_earning)), new Decimal(0));
    return total;
  }, [productionLogs]);

  const mainPadding = isCollapsed ? "pl-[60px]" : "pl-[240px]";

  if (karigarLoading) return <ProfileSkeleton padding={mainPadding} />;

  return (
    <div className="min-h-screen bg-onyx text-slate-200">
      <IndustrialSidebar />

      <main className={`${mainPadding} transition-all duration-300 pb-20`}>
        <header className="h-16 border-b border-white/5 flex items-center px-8 bg-surface/50 backdrop-blur-md sticky top-0 z-40">
           <Link href="/karigars" className="mr-4 p-2 hover:bg-white/5 transition-colors text-gray-500 hover:text-white">
              <ChevronLeft size={20} />
           </Link>
           <h1 className="text-xl font-semibold text-white tracking-tight">{karigar.name} Profile</h1>

           <div className="ml-auto flex items-center space-x-3">
              <button className="px-4 py-2 border border-white/10 text-[10px] uppercase font-bold text-gray-400 hover:text-white hover:bg-white/5 transition-all">
                 Generate ID Card
              </button>
              <button className="px-4 py-2 bg-electric-blue text-onyx text-[10px] uppercase font-black tracking-widest hover:brightness-110">
                 Edit Personnel File
              </button>
           </div>
        </header>

        <div className="p-8 max-w-[1600px] mx-auto">
           <div className="grid grid-cols-12 gap-8">

              {/* Left Sidebar Profile */}
              <div className="col-span-12 lg:col-span-4 space-y-6">
                 <div className="bg-surface border border-white/5 p-8 text-center space-y-6">
                    <div className="w-32 h-32 rounded-full overflow-hidden mx-auto border-4 border-onyx shadow-2xl relative group">
                       {karigar.photo_url ? (
                         <Image src={karigar.photo_url} alt={karigar.name} fill className="object-cover" />
                       ) : (
                         <div className="w-full h-full bg-onyx flex items-center justify-center text-4xl font-bold text-gray-800">
                            {karigar.name.substring(0, 2).toUpperCase()}
                         </div>
                       )}
                    </div>

                    <div className="space-y-1">
                       <h2 className="text-2xl font-bold text-white tracking-tight">{karigar.name}</h2>
                       <p className="text-sandstone-gold font-mono text-sm font-bold">{karigar.karigar_code}</p>
                       <div className="flex items-center justify-center space-x-2 mt-2">
                          <span className="px-2 py-0.5 bg-emerald/10 text-emerald text-[9px] uppercase font-black rounded-sm">{karigar.status}</span>
                          <span className="px-2 py-0.5 bg-white/5 text-gray-400 text-[9px] uppercase font-black rounded-sm">{karigar.karigar_grades?.grade_name || 'Un-Graded'}</span>
                       </div>
                    </div>

                    <div className="pt-6 border-t border-white/5 grid grid-cols-2 gap-4 text-left">
                       <ProfileStat label="Pay Model" value={karigar.wage_type.replace('_', ' ')} />
                       <ProfileStat label="Current Rate" value={fmt(karigar.piece_rate || karigar.daily_rate || karigar.monthly_salary || 0)} />
                       <ProfileStat label="Tenure" value={tenure} />
                       <ProfileStat label="Joined" value={fmtDate(karigar.joining_date)} />
                    </div>
                 </div>

                 <div className="bg-surface border border-white/5 p-6 space-y-4">
                    <h3 className="text-[10px] uppercase font-black text-gray-500 tracking-widest border-b border-white/5 pb-2">Verified Documents</h3>
                    <DocItem label="CNIC / National ID" value={karigar.cnic || "Not Provided"} icon={Award} />
                    <DocItem label="Mobile Number" value={karigar.phone || "Not Provided"} icon={Phone} />
                    <DocItem label="Residential Address" value={karigar.address || "Not Provided"} icon={MapPin} />
                    <DocItem label="Bank Account" value={karigar.bank_account || "Not Provided"} icon={CreditCard} />
                 </div>
              </div>

              {/* Right Main Content */}
              <div className="col-span-12 lg:col-span-8 space-y-8">
                 {/* Tabs Nav */}
                 <div className="flex border-b border-white/5">
                    {[
                      { id: 'production', label: 'Production Log', icon: BarChart3 },
                      { id: 'attendance', label: 'Attendance', icon: Clock },
                      { id: 'advances', label: 'Advances (Peshgi)', icon: Banknote },
                      { id: 'payslips', label: 'Payslips', icon: FileText },
                    ].map(tab => (
                      <button 
                        key={tab.id}
                        onClick={() => setActiveTab(tab.id as 'production' | 'attendance' | 'advances' | 'payslips')}
                        className={cn(
                          "px-6 py-4 flex items-center space-x-2 text-[10px] uppercase font-black tracking-widest transition-all relative",
                          activeTab === tab.id ? "text-electric-blue" : "text-gray-500 hover:text-white"
                        )}
                      >
                         <tab.icon size={14} />
                         <span>{tab.label}</span>
                         {activeTab === tab.id && <motion.div layoutId="tab-underline" className="absolute bottom-0 left-0 right-0 h-0.5 bg-electric-blue" />}
                      </button>
                    ))}
                 </div>

                 <div className="min-h-[500px]">
                    <AnimatePresence mode="wait">
                       {activeTab === 'production' && (
                         <motion.div initial={{ opacity: 0, x: 10 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -10 }} className="space-y-6">
                            <div className="flex items-center justify-between">
                               <h3 className="text-lg font-bold text-white tracking-tight">Performance Analytics</h3>
                               <div className="text-right">
                                  <p className="text-[10px] uppercase font-bold text-gray-500">Mtd Earnings</p>
                                  <p className="text-2xl font-mono text-sandstone-gold font-bold">{fmt(monthlyEarnings)}</p>
                               </div>
                            </div>

                            <div className="bg-surface border border-white/5 overflow-hidden">
                               <table className="w-full text-left">
                                  <thead className="bg-onyx border-b border-white/10">
                                     <tr>
                                        <th className="px-6 py-4 text-[10px] uppercase font-black text-gray-500">Log Date</th>
                                        <th className="px-6 py-4 text-[10px] uppercase font-black text-gray-500">Item Type</th>
                                        <th className="px-6 py-4 text-[10px] uppercase font-black text-gray-500 text-right">Qty</th>
                                        <th className="px-6 py-4 text-[10px] uppercase font-black text-gray-500 text-right">Earnings</th>
                                     </tr>
                                  </thead>
                                  <tbody>
                                     {productionLogs.length === 0 ? (
                                       <tr><td colSpan={4} className="px-6 py-12 text-center text-[10px] uppercase font-bold text-gray-700 tracking-widest">No production data detected</td></tr>
                                     ) : (
                                       productionLogs.map((log: ProductionLog, i: number) => (
                                         <tr key={log.id} className={cn("border-b border-white/5", i % 2 === 1 && "bg-white/[0.01]")}>
                                            <td className="px-6 py-4 text-xs text-gray-400">{fmtDate(log.log_date)}</td>
                                            <td className="px-6 py-4 text-xs text-white uppercase font-bold">{log.unit}</td>
                                            <td className="px-6 py-4 text-xs font-mono text-white text-right">{log.qty_produced}</td>
                                            <td className="px-6 py-4 text-xs font-mono text-sandstone-gold text-right">{fmt(log.effective_earning)}</td>
                                         </tr>
                                       ))
                                     )}
                                  </tbody>
                               </table>
                            </div>
                         </motion.div>
                       )}

                       {activeTab === 'attendance' && (
                         <motion.div initial={{ opacity: 0, x: 10 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -10 }} className="space-y-6">
                            <h3 className="text-lg font-bold text-white tracking-tight">Attendance Record</h3>
                            <div className="bg-surface border border-white/5 overflow-hidden">
                               <table className="w-full text-left">
                                  <thead className="bg-onyx border-b border-white/10">
                                     <tr>
                                        <th className="px-6 py-4 text-[10px] uppercase font-black text-gray-500">Date</th>
                                        <th className="px-6 py-4 text-[10px] uppercase font-black text-gray-500">Status</th>
                                        <th className="px-6 py-4 text-[10px] uppercase font-black text-gray-500">Notes</th>
                                     </tr>
                                  </thead>
                                  <tbody>
                                     attendanceLogs.map((log: AttendanceLog, i: number) => (
                                       <tr key={log.id} className={cn("border-b border-white/5", i % 2 === 1 && "bg-white/[0.01]")}>
                                          <td className="px-6 py-4 text-xs text-gray-400">{fmtDate(log.log_date)}</td>
                                          <td className="px-6 py-4">
                                             <span className={cn(
                                               "px-2 py-0.5 text-[9px] uppercase font-black rounded-sm",
                                               log.status === 'present' ? "bg-emerald/10 text-emerald" : 
                                               log.status === 'absent' ? "bg-critical-red/10 text-critical-red" : 
                                               "bg-amber-500/10 text-amber-500"
                                             )}>{log.status}</span>
                                          </td>
                                          <td className="px-6 py-4 text-xs text-gray-500 italic">&quot;{log.notes || '---'}&quot;</td>
                                       </tr>
                                     ))}
                                  </tbody>
                               </table>
                            </div>
                         </motion.div>
                       )}

                       {activeTab === 'advances' && (
                         <motion.div initial={{ opacity: 0, x: 10 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -10 }} className="space-y-6">
                            <div className="flex items-center justify-between">
                               <h3 className="text-lg font-bold text-white tracking-tight">Advance Ledger (Peshgi)</h3>
                               <div className="text-right">
                                  <p className="text-[10px] uppercase font-bold text-gray-500">Outstanding Bal.</p>
                                  <p className="text-2xl font-mono text-critical-red font-bold">{fmt(karigar.current_advance)}</p>
                               </div>
                            </div>

                            <div className="bg-surface border border-white/5 overflow-hidden">
                               <table className="w-full text-left">
                                  <thead className="bg-onyx border-b border-white/10">
                                     <tr>
                                        <th className="px-6 py-4 text-[10px] uppercase font-black text-gray-500">Date</th>
                                        <th className="px-6 py-4 text-[10px] uppercase font-black text-gray-500">Amount</th>
                                        <th className="px-6 py-4 text-[10px] uppercase font-black text-gray-500">Reason</th>
                                        <th className="px-6 py-4 text-[10px] uppercase font-black text-gray-500 text-right">Status</th>
                                     </tr>
                                  </thead>
                                  <tbody>
                                     advances.map((adv: Advance, i: number) => (
                                       <tr key={adv.id} className={cn("border-b border-white/5", i % 2 === 1 && "bg-white/[0.01]")}>
                                          <td className="px-6 py-4 text-xs text-gray-400">{fmtDate(adv.advance_date)}</td>
                                          <td className="px-6 py-4 text-xs font-mono text-sandstone-gold font-bold">{fmt(adv.amount)}</td>
                                          <td className="px-6 py-4 text-xs text-white uppercase font-medium">{adv.reason}</td>
                                          <td className="px-6 py-4 text-right">
                                             <span className={cn(
                                               "px-2 py-0.5 text-[9px] uppercase font-black rounded-sm",
                                               adv.status === 'pending' ? "bg-amber-500/10 text-amber-500" : "bg-emerald/10 text-emerald"
                                             )}>{adv.status}</span>
                                          </td>
                                       </tr>
                                     ))}
                                  </tbody>
                               </table>
                            </div>
                         </motion.div>
                       )}

                       {activeTab === 'payslips' && (
                         <motion.div initial={{ opacity: 0, x: 10 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -10 }} className="flex flex-col items-center justify-center h-full py-20 space-y-6">
                            <div className="w-16 h-16 bg-onyx rounded-full flex items-center justify-center text-gray-800">
                               <FileText size={32} />
                            </div>
                            <div className="text-center">
                               <p className="text-white font-bold uppercase tracking-widest">Digital Payslip Vault</p>
                               <p className="text-gray-500 text-xs mt-2">Historical payroll distributions for this {workerTerm.toLowerCase()}.</p>
                            </div>
                            <button className="px-6 py-3 bg-white/5 border border-white/10 text-[10px] uppercase font-bold text-gray-400 hover:text-white transition-all">
                               Access Vault
                            </button>
                         </motion.div>
                       )}
                    </AnimatePresence>
                 </div>
              </div>
           </div>
        </div>
      </main>
    </div>
  );
}

// --- Sub-Components ---

function ProfileStat({ label, value }: { label: string, value: string }) {
  return (
    <div className="space-y-1">
       <p className="text-[9px] uppercase font-bold text-gray-600 tracking-widest">{label}</p>
       <p className="text-xs font-bold text-white truncate">{value}</p>
    </div>
  );
}

function DocItem({ label, value, icon: Icon }: { label: string, value: string, icon: React.ElementType }) {
  return (
    <div className="flex items-start space-x-3">
       <div className="p-2 bg-onyx border border-white/5 text-gray-700">
          <Icon size={14} />
       </div>
       <div className="space-y-0.5">
          <p className="text-[9px] uppercase font-bold text-gray-600 tracking-widest">{label}</p>
          <p className="text-xs text-white/80">{value}</p>
       </div>
    </div>
  );
}

function ProfileSkeleton({ padding }: { padding: string }) {
  return (
    <div className="min-h-screen bg-onyx">
      <IndustrialSidebar />
      <main className={`${padding} p-8 space-y-8 animate-pulse`}>
         <div className="h-16 bg-surface border border-white/5" />
         <div className="grid grid-cols-12 gap-8">
            <div className="col-span-4 h-[600px] bg-surface border border-white/5" />
            <div className="col-span-8 h-[600px] bg-surface border border-white/5" />
         </div>
      </main>
    </div>
  );
}
